// 전역 변수
scwin.memJson = $c.data.getMemInfo();

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.isSubCompany = false;
scwin.checkSearch;

scwin.dateStr     = $c.date.getServerDateTime("yyyyMMdd");

scwin.onpageload = function() {

    const codeOptions = [
        { grpCd : "FI019", compID : "rd_pchsSellClsCd" },
        { grpCd : "CO030", compID : "lc_sysCd" }
    ];
    $c.data.setCommonCode(codeOptions);   

};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search,[ed_srchCloseYm]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
    $c.gus.cfInitHidVal(tbl_search);
    ed_srchCloseYm.setValue( scwin.dateStr.substring(0,6) );
    rd_pchsSellClsCd.setValue(1);
    ed_srchCloseYm.focus();
}

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableKey();
    scwin.f_FieldClear();

    //rd_pchsSellClsCd.setSelectedIndex(1);
    //rd_pchsSellClsCd.setValue("1");

    //테스트용
    //ed_srchCloseYm.setValue("200907");
    //ed_srchAcctDeptCd.setValue("00206");

    scwin.f_setCompanyInfo();
}

//-------------------------------------------------------------------------
// CommonCode 세팅 후 초기화
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
    rd_pchsSellClsCd.setSelectedIndex(0);
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {   
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU ;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);

    scwin.f_PopUpCompanyInfo('T'); 

    $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);   

}   

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF) {
    udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
    									,ed_coCd.getValue(), ed_coNm.getValue()
    									,pWinCloseTF,null,null,null,null
    									,null,null,null,null,null);   
}

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    // SET
console.log(rtnList)  ;
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명
    } else {
        ed_coNm.setValue("");
        ed_coCd.setValue("");
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F',ed_coCd,ed_coNm);
};

//-------------------------------------------------------------------------
// 회사코드 입력시
//-------------------------------------------------------------------------
scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

scwin.udc_clntCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_clntCd,ed_clntNm,'1','ALL');
};


scwin.f_openPopUp = function(orgObjCd, orgObjNm, select_code, flag) {


	// POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
	// 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
	if (flag == "ALL") {
		cd = "";
		nm = "";
	} else {
		cd = orgObjCd.getValue();
		nm = orgObjNm.getValue();
	}

  	switch (select_code) {
		// 조회조건용 거래처 PopUp 호출
		 case '1' :
			var pWhere = ed_coCd.getValue();
	  		udc_clntCd.cfCommonPopUp(scwin.udc_clntCd_callBackFunc,cd,nm,"T",null,null,null,null,pWhere,null,null,null,null); // 거래처(모든 거래처를 다 조회한다.)
			scwin.checkSearch = false;	// 정상조회여부 확인
		 	break;

		case '11':
	 	// 계정조회   	  	
   	  	    var temp = "T,,,,,";
	        udc_mgntAcctCd.cfCommonPopUp(scwin.udc_mgntAcctCd_callBackFunc,ed_mgntAcctCd.getValue().trim(),ed_mgntAcctNm.getValue().trim().value,null,null,null,null,null,temp,null,null,null,null); 

            break;

		default:	
	    break;


	}
}

//거래처
scwin.udc_clntCd_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_clntCd.setValue( rtnList[0] );	// 코드값
        ed_clntNm.setValue( rtnList[1] );	// 코드명
        ed_DeptCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
        ed_DeptNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_clntCd.setValue("");
        ed_clntNm.setValue("");
        ed_DeptCd.options.hidVal = "";
        ed_DeptNm.options.hidVal = "";
    }
}

//계정
scwin.udc_mgntAcctCd_callBackFunc = function(rtnList) {
    if (rtnList != null ) {
        if ( rtnList[0] == "N/A" ) return ;
        ed_clntCd.setValue( rtnList[0] );	// 코드값
        ed_clntNm.setValue( rtnList[1] );	// 코드명
        //ed_DeptCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
        //ed_DeptNm.options.hidVal = rtnList[1];	// HIDDEN 코드명
    } else {
        ed_clntCd.setValue("");
        ed_clntNm.setValue("");
        //ed_DeptCd.options.hidVal = "";
        //ed_DeptNm.options.hidVal = "";
    }
}

scwin.udc_srchAcctDeptCd_onclickEvent = function (e) {
    scwin.f_deptPopUpClick();
};

//-------------------------------------------------------------------------
// 부서코드팝업 클릭시
// 옵션이 AsIs랑 달라 
//-------------------------------------------------------------------------
scwin.f_deptPopUpClick = function() {
    //<-- <수정_070105_신종민> 귀속변경에 따른 병행처리 수정 
    var sQueryID = '';
    var pWhere = '';
    if ( ed_srchCloseYm.getValue().substring(0,4).trim() == '2006' ){
        sQueryID = 'retrieveAcctDeptCdInfoBef';
    }else{

        pWhere =  ",,,,,,,,,"+ed_coCd.getValue();   
        sQueryID = 'retrieveAcctDeptCdInfo';
    }

    udc_srchAcctDeptCd.setSelectId(sQueryID);
    udc_srchAcctDeptCd.cfCommonPopUp(
        scwin.udc_srchAcctDeptCd_callBackFunc, 
        ed_srchAcctDeptCd.getValue(),
        ed_srchAcctDeptNm.getValue(),
        "F", // auto close 1건  닫기
        null,
        null,
        null,
        null,
        pWhere,
        null,
        null,
        null,
        null,
        null,
        'T'//전체검색
        );



    //-->
}

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function() {
    //<-- <수정_070105_신종민> 귀속변경에 따른 병행처리 수정 
    if ( ed_srchCloseYm.getValue().substring(0,4).trim() == '2006' ){
