scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 조회(미확정거래내역집계)
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {

    let ret;
    //ed_srchCloseYm 예산년월은 잠시 cfValidate 에서 제외한다.
    //ed_srchCloseYm 제외 : invalidMessage 설정하는 곳이 없어 cfValidate 에 넣어 사용할 수 없다.
    ret = await $c.gus.cfValidate([ed_srchCloseYm,ed_srchAcctDeptCd]);
    if (!ret)
        return false;

//alert("hidval : " + ed_srchAcctDeptCd.options.hidVal  );
    if (ed_srchAcctDeptCd.getValue() != ed_srchAcctDeptCd.options.hidVal) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["부서"]);
        ed_srchAcctDeptCd.focus();
        return false;
    }

    //ds_search.UseChangeInfo = false;
    //tr_search.post();

    //소스에서 바인딩 하는게 더 수월
    dma_search.set("closeYm", ed_srchCloseYm.getValue());   //마감년월
    dma_search.set("clntCd", ed_clntCd.getValue()); // 거래처
    dma_search.set("acctDeptCd", ed_srchAcctDeptCd.getValue()); // 부서
    dma_search.set("pchsSellClsCd", rd_pchsSellClsCd.getValue()); // 매출입구분
    dma_search.set("sysCd", lc_sysCd.getValue());   // 시스템구분
    dma_search.set("mgntAcctCd", ed_mgntAcctCd.getValue()); // 계정코드
    dma_search.set("coCd", ed_coCd.getValue())

    $c.sbm.execute(sbm_search);
}

scwin.sbm_search_submitdone = function(e) {
    ed_totalRows.setValue( ds_master2.getRowCount() );

    //강제 position 주기
    ds_master2.setRowPosition(0);

    //alert( tac_tab.getSelectedTabID() );
    //tac_tab.getSelectedTabID()
    var activatedTab = tac_tab.getSelectedTabID();
    var childTab = tac_tab.getWindow(activatedTab);
    console.log("childTab=>" + childTab);      

    if ( ds_master2.getRowCount() == 0) {
        childTab.ds_master.removeAll();
        if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    } else {
			$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
	} else {


        if (childTab) {
    /*
            iFrame0.ds_search.NameValue(1,"closeYm")       = ds_search.NameValue(1,"closeYm");
            iFrame0.ds_search.NameValue(1,"clntCd")        = ds_master2.NameValue(ds_master2.RowPosition,"reqClntNo");
            iFrame0.ds_search.NameValue(1,"acctDeptCd")    = ds_master2.NameValue(ds_master2.RowPosition,"acctDeptCd")
            iFrame0.ds_search.NameValue(1,"mgntAcctCd")    = ds_search.NameValue(1,"mgntAcctCd"); 	            
            iFrame0.ds_search.NameValue(1,"sysd")          = ds_search.NameValue(1,"sysd"); 	            	               
            iFrame0.ds_search.NameValue(1,"pchsSellClsCd") = ds_search.NameValue(1,"pchsSellClsCd")
            iFrame0.ds_search.NameValue(1,"odrNo")         = "";
    */

            // 3. 자식 화면의 JavaScript Scope 내 DataMap에 접근하여 값 설정
            // subWin.자식화면컴포넌트ID
            childTab.dma_search.set("closeYm", dma_search.get("closeYm") );
            childTab.dma_search.set("clntCd", ds_master2.getCellData( ds_master2.getRowPosition(),"reqClntNo") );
            childTab.dma_search.set("acctDeptCd", ds_master2.getCellData( ds_master2.getRowPosition(),"acctDeptCd") );
            childTab.dma_search.set("mgntAcctCd", dma_search.get("mgntAcctCd") );
            childTab.dma_search.set("sysd", dma_search.get("sysd") );
            childTab.dma_search.set("pchsSellClsCd", dma_search.get("pchsSellClsCd") );
            childTab.dma_search.set("odrNo", "");

            //개선 요청 명칭도 표기 되게 2026 03 23
            childTab.ed_srchAcctDeptNm.setValue(ds_master2.getCellData( ds_master2.getRowPosition(),"acctDeptNm")  );
            childTab.ed_clntNm.setValue( ds_master2.getCellData( ds_master2.getRowPosition(),"reqClntNm") );

            //alert( childTab );
            //debugger;
            //alert("$c.sbm.execute right?");
            //$c.sbm.execute( childTab.sbm_search );
            //$c.sbm.execute(sbmObj, requestData, compObj)
            //childTab.$c.sbm.execute( sbm_search );

            childTab.scwin.execute_sbm_search();
        }
    }

    //debugger;

}

//소계컬럼에 targetColumnID 값 세팅
scwin.subtotalTargetColumnView = function(rowIndex, tci) {
