};



scwin.sbm_search_submiterror = function(e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
    //cfShowError(ds_master2);
}
scwin.udc_srchAcctDeptCd_onblurCodeEvent = function (e) {
    if (scwin.f_IsPopUp(ed_srchAcctDeptCd, ed_srchAcctDeptNm)) scwin.f_deptPopUp('F');
};

//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function(inObj, ...pairObjs) {
    let inValue = $c.gus.cfGetValue(inObj);

    if (!inObj.options) inObj.options = {};
    let hidValue = inObj.options.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.options.hidVal = "";
        for (let i = 0; i < pairObjs.length; i++) {
            $c.gus.cfSetValue(pairObjs[i], "");
        }
        return false;
    }

    if (inValue == hidValue) return false;

    return true;
};    
scwin.udc_mgntAcctCd_onblurCodeEvent = function (e) {
    if (scwin.f_IsPopUp(ed_mgntAcctCd, ed_mgntAcctNm)) scwin.f_acctPopUp();
};

scwin.udc_mgntAcctCd_onclickEvent = function (e) {
