scwin.gr_master2_oncellclick = function (rowIndex, columnIndex, columnId) {
    var activatedTab = tac_tab.getSelectedTabID();
    var childTab = tac_tab.getWindow(activatedTab);
    console.log("childTab=>" + childTab);      


    if (childTab) {

        // 3. 자식 화면의 JavaScript Scope 내 DataMap에 접근하여 값 설정
        // subWin.자식화면컴포넌트ID
        childTab.dma_search.set("closeYm", dma_search.get("closeYm") );
        childTab.dma_search.set("clntCd", ds_master2.getCellData( rowIndex,"reqClntNo") );
        childTab.dma_search.set("acctDeptCd", ds_master2.getCellData( rowIndex,"acctDeptCd") );
        childTab.dma_search.set("mgntAcctCd", dma_search.get("mgntAcctCd") );
        childTab.dma_search.set("sysd", dma_search.get("sysd") );
        childTab.dma_search.set("pchsSellClsCd", dma_search.get("pchsSellClsCd") );
        childTab.dma_search.set("odrNo", "");

        childTab.ed_srchAcctDeptNm.setValue(ds_master2.getCellData( ds_master2.getRowPosition(),"acctDeptNm")  );
        childTab.ed_clntNm.setValue( ds_master2.getCellData( ds_master2.getRowPosition(),"reqClntNm") );

        //alert( childTab );
        //alert("$c.sbm.execute right?");
        //let ret;
        //ret = await $c.sbm.execute( childTab.sbm_search );
        //await $c.sbm.execute( childTab.sbm_search );

        //await childTab.$p.submit("sbm_search");
        childTab.scwin.execute_sbm_search();

    }


    //debugger;
};

scwin.tac_tab_onchange = function (tabId, index, userTabId) {
console.log("tabId=>" + tabId);
console.log("index=>" + index);
console.log("userTabId=>" + userTabId);

var rowIndex = ds_master2.getRowPosition();
    var activatedTab = tac_tab.getSelectedTabID();
    var childTab = tac_tab.getWindow(activatedTab);
    console.log("childTab=>" + childTab);

    childTab.dma_search.set("closeYm", dma_search.get("closeYm") );

    if(ds_master2.getRowCount() > 0) {
        childTab.dma_search.set("clntCd", ds_master2.getCellData( rowIndex,"reqClntNo") );
        childTab.dma_search.set("acctDeptCd", ds_master2.getCellData( rowIndex,"acctDeptCd") );
    }
    childTab.dma_search.set("mgntAcctCd", dma_search.get("mgntAcctCd") );
    childTab.dma_search.set("sysd", dma_search.get("sysd") );
    childTab.dma_search.set("pchsSellClsCd", dma_search.get("pchsSellClsCd") );

    //개선 요청 명칭도 표기 되게 2026 03 23
    childTab.ed_srchAcctDeptNm.setValue(ds_master2.getCellData( ds_master2.getRowPosition(),"acctDeptNm")  );
    childTab.ed_clntNm.setValue( ds_master2.getCellData( ds_master2.getRowPosition(),"reqClntNm") );

    //childTab.dma_search.set("odrNo", "");

};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function(){

	if(ds_master2.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let filename = '미확정거래내역(집계)_' + ed_srchCloseYm.getValue() + "_" + ed_srchAcctDeptNm.getValue() + "_" + rd_pchsSellClsCd.getText();
    const options = {
        fileName: filename + ".xlsx",
        sheetName: filename
    };
    $c.data.downloadGridViewExcel(gr_master2, options);

};
